-- Case 010: dynamic table with nested query, target lag, cluster key, and frozen region
CREATE OR REPLACE DYNAMIC TABLE MART.DT_CUSTOMER_360_DAILY(snapshot_date DATE,tenant_id STRING,customer_id STRING,region STRING,order_count NUMBER,gross_amount NUMBER(18,4),last_order_at TIMESTAMP_TZ,support_ticket_count NUMBER,risk_flags ARRAY,customer_features OBJECT) TARGET_LAG = '30 minutes' WAREHOUSE = FORMATTER_TEST_WH REFRESH_MODE = AUTO INITIALIZE = ON_CREATE CLUSTER BY(snapshot_date,tenant_id,region) FROZEN WHERE(snapshot_date < CURRENT_DATE() - 30) WITH TAG(GOVERNANCE.PIPELINE = 'customer_360',GOVERNANCE.QUALITY = 'gold') AS WITH orders AS(SELECT order_date AS snapshot_date,tenant_id,customer_id,region,COUNT(*) AS order_count,SUM(gross_amount) AS gross_amount,MAX(order_at) AS last_order_at FROM CORE.FACT_ORDER WHERE order_date >= CURRENT_DATE() - 400 GROUP BY order_date,tenant_id,customer_id,region),tickets AS(SELECT DATE_TRUNC( 'day',created_at)::DATE AS snapshot_date,tenant_id,customer_id,COUNT_IF(status <> 'closed') AS support_ticket_count,ARRAY_AGG(DISTINCT severity) WITHIN GROUP(ORDER BY severity) AS ticket_severities FROM CORE.SUPPORT_TICKET WHERE created_at >= DATEADD( 'day',-400,CURRENT_TIMESTAMP()) GROUP BY 1,tenant_id,customer_id),risk AS(SELECT tenant_id,customer_id,ARRAY_AGG(flag) WITHIN GROUP(ORDER BY weight DESC,flag) AS risk_flags FROM CORE.CUSTOMER_RISK_FLAG WHERE active GROUP BY tenant_id,customer_id) SELECT o.snapshot_date,o.tenant_id,o.customer_id,o.region,o.order_count,o.gross_amount,o.last_order_at,COALESCE(t.support_ticket_count,0) AS support_ticket_count,COALESCE(r.risk_flags,ARRAY_CONSTRUCT()) AS risk_flags,OBJECT_CONSTRUCT_KEEP_NULL( 'ticket_severities',t.ticket_severities, 'avg_order_value',DIV0(o.gross_amount,o.order_count), 'days_since_last_order',DATEDIFF( 'day',o.last_order_at,CURRENT_TIMESTAMP())) AS customer_features FROM orders AS o LEFT JOIN tickets AS t ON o.snapshot_date = t.snapshot_date AND o.tenant_id = t.tenant_id AND o.customer_id = t.customer_id LEFT JOIN risk AS r ON o.tenant_id = r.tenant_id AND o.customer_id = r.customer_id;
